const { context, history, sessionId, userMessage } = $input.first().json;
// Обязательные поля для составления СЗ
const required = ['violation_date', 'employee_name', 'employee_position', 'manager_name', 'manager_position', 'prior_behavior', 'contact_attempts', 'consequences'];
const missing = required.filter(k => !context[k]);
const isReady = missing.length === 0;
return [{ json: { context, history, sessionId, userMessage, isReady, missing } }];

const { context, history, sessionId, userMessage } = $input.first().json;
const today = new Date().toLocaleDateString('ru-RU');
const systemPrompt = `Ты — HR-ассистент. Составь служебную записку о дисциплинарном нарушении.
СТРОГО только факты из данных ниже — ничего не додумывай, не предполагай.
Если данных не хватает — пиши [УТОЧНИТЬ].

Данные:
${JSON.stringify(context, null, 2)}

Дата составления: ${today}

Структура служебной записки:
1. Шапка: кому, от кого, организация, дата
2. Факт нарушения: что / когда точно / где / кто
3. Обстоятельства нарушения
4. Предшествующее поведение сотрудника
5. Каналы связи (попытки выяснить причины)
6. Нарушенные НПА
7. Негативные последствия
8. Просьба провести проверку
9. Приложения`;
const messages = [
  { role: 'system', content: systemPrompt },
  ...history,
  { role: 'user', content: 'Составь служебную записку на основе собранных данных.' }
];
return [{ json: { messages, sessionId, userMessage, context, generateMode: true } }];

const llmResult = $input.first().json;
const szText = llmResult.response || '';
return [{ json: {
  output: `Служебная записка готова:\n\n${szText}\n\nПередайте пакет документов (акт + СЗ) эксперту кадрового учёта — Черепановой Т. или Касмыниной О.`,
  newState: 'DONE'
} }];

const { context, history, sessionId, userMessage, missing } = $input.first().json;
const missingLabels = {
  violation_date: 'дата нарушения',
  employee_name: 'ФИО сотрудника',
  employee_position: 'должность сотрудника',
  manager_name: 'ФИО руководителя (ваше ФИО)',
  manager_position: 'должность руководителя',
  prior_behavior: 'предшествующее поведение сотрудника',
  contact_attempts: 'попытки связаться с сотрудником',
  consequences: 'последствия для подразделения'
};
const missingText = missing.map(k => missingLabels[k] || k).join(', ');
const systemPrompt = `Ты — HR-ассистент. Составляем служебную записку о дисциплинарном нарушении.

Уже известно:
${JSON.stringify(context, null, 2)}

Для составления СЗ ещё не хватает: ${missingText}.

Запроси недостающие данные у руководителя. Задавай вопросы по одному, не засыпай сразу всем.
Только факты — ничего не додумывай.

Когда руководитель называет конкретные данные — добавь в конец ответа ОТДЕЛЬНОЙ строкой:
DATA_UPDATE: {"field_name": "value"}
Где field_name — название поля из: prior_behavior, contact_attempts, consequences, employee_name, employee_position, manager_name, manager_position.
Если данных несколько — перечисли все поля в одном объекте.
Если новых данных нет — не добавляй DATA_UPDATE.`;
const messages = [
  { role: 'system', content: systemPrompt },
  ...history,
  { role: 'user', content: userMessage }
];
return [{ json: { messages, sessionId, userMessage, context } }];

const llmResult = $input.first().json;
const prev = $('СБОР ДАННЫХ: сформировать промпт').item.json;
// Ищем DATA_UPDATE маркер (LLM должен добавить если распознал данные)
const responseText = llmResult.response || '';
let contextUpdate = {};
const dataMatch = responseText.match(/DATA_UPDATE:\s*(\{[^}]+\})/);
if (dataMatch) {
  try { contextUpdate = JSON.parse(dataMatch[1]); } catch(e) {}
}
const cleanResponse = responseText.replace(/DATA_UPDATE:[\s\S]*$/, '').trim();
return [{ json: {
  output: cleanResponse,
  newState: 'BUILD_SZ',
  contextUpdate
} }];
